mapper.select:
SELECT id, message_id, session_id, agent_id, user_id, role, content, token_count, created_at
FROM (
    SELECT id, message_id, session_id, agent_id, user_id, role, content, token_count, created_at
    FROM chat_message
    WHERE session_id = #{sessionId}
    ORDER BY created_at DESC
    LIMIT #{limit}
) t
ORDER BY created_at ASC

SELECT COUNT(*)
FROM chat_message
WHERE session_id = #{sessionId}
